import React, { useEffect, useMemo, useState } from "react";
import ResultCart from "./ResultCart";

const Add = () => {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const tmdbKey = useMemo(() => process.env.REACT_APP_TMDB_KEY, []);
  const safeQuery = query.trim();

  useEffect(() => {
    const MIN_QUERY_LENGTH = 2;

    if (!tmdbKey) {
      setErrorMessage("TMDB API key tanımlı değil. .env dosyasını kontrol edin.");
      setResults([]);
      setIsLoading(false);
      return;
    }

    if (safeQuery.length < MIN_QUERY_LENGTH) {
      setErrorMessage("");
      setResults([]);
      setIsLoading(false);
      return;
    }

    // CRA'da env vars build/start anında okunur; token/api-key type'ını buradan belirliyoruz.
    const isBearerToken = typeof tmdbKey === "string" && tmdbKey.startsWith("eyJ");
    const encodedQuery = encodeURIComponent(safeQuery);

    const controller = new AbortController();
    const timeoutId = window.setTimeout(() => {
      setIsLoading(true);

      fetch(
        isBearerToken
          ? `https://api.themoviedb.org/3/search/movie?language=en-US&page=1&include_adult=false&query=${encodedQuery}`
          : `https://api.themoviedb.org/3/search/movie?api_key=${tmdbKey}&language=en-US&page=1&include_adult=false&query=${encodedQuery}`,
        isBearerToken
          ? {
              headers: {
                Authorization: `Bearer ${tmdbKey}`,
              },
              signal: controller.signal,
            }
          : { signal: controller.signal }
      )
        .then(async (res) => {
          const data = await res.json().catch(() => ({}));

          if (!res.ok) {
            if (res.status === 401) {
              setErrorMessage("TMDB 401: API key/token yanlış ya da eksik.");
            } else {
              setErrorMessage(`TMDB ${res.status}: İstek başarısız.`);
            }
            setResults([]);
            return;
          }

          const safeResults = Array.isArray(data?.results) ? data.results : [];
          setErrorMessage("");
          setResults(safeResults);
        })
        .catch((err) => {
          // Unmount/next search durumlarında abort olabiliyor.
          if (err?.name === "AbortError") return;
          setErrorMessage("Arama sırasında bir hata oluştu.");
          setResults([]);
        })
        .finally(() => setIsLoading(false));
    }, 350);

    return () => {
      window.clearTimeout(timeoutId);
      controller.abort();
    };
  }, [safeQuery, tmdbKey]);

  function onChange(e) {
    const nextQuery = e.target.value;
    setQuery(nextQuery);
  }

  function onClear() {
    setQuery("");
    setResults([]);
    setErrorMessage("");
    setIsLoading(false);
  }

  return (
    <div className="add-page">
      <div className="container">
        <div className="add-content">
          <img
            src="https://www.themoviedb.org/t/p/w1920_and_h600_multi_faces_filter(duotone,032541,01b4e4)/9ZyAUZrfccsjtDwYgc7yvOBnqM9.jpg"
            alt="Film arama arka plan görseli"
          />
          <div className="titles">
            <h1>Hoş Geldiniz.</h1>
            <h2>
              Milyonlarca film, TV şovu ve keşfedilecek kişi. Şimdi keşfedin.
            </h2>
          </div>
          <div className="input-wrapper">
            <input
              type="text"
              value={query}
              onChange={onChange}
              placeholder="Film, dizi, kişi ara..."
            />
            <button className="clear-btn" type="button" onClick={onClear}>
              Temizle
            </button>
          </div>

          {errorMessage && <p className="add-error">{errorMessage}</p>}
          {isLoading && <div className="add-loading">Aranıyor...</div>}

          {!isLoading &&
            !errorMessage &&
            safeQuery.length >= 2 &&
            results.length === 0 && (
              <p className="add-empty">Sonuç bulunamadı.</p>
            )}

          {results.length > 0 && (
            <ul className="results">
              {results.map((movie) => (
                <li key={movie.id}>
                  <ResultCart movie={movie} />
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
};

export default Add;
